#!/bin/bash
IFS=. read -r i1 i2 i3 i4 <<< "$1"; m=$((0xffffffff << (32 - $2))); n=$(( (i1<<24 | i2<<16 | i3<<8 | i4) & m )); b=$(( n | ~m & 0xffffffff )); printf "%d.%d.%d.%d - %d.%d.%d.%d\n" $(( (n+1)>>24 & 255 )) $(( (n+1)>>16 & 255 )) $(( (n+1)>>8 & 255 )) $(( (n+1) & 255 )) $(( (b-1)>>24 & 255 )) $(( (b-1)>>16 & 255 )) $(( (b-1)>>8 & 255 )) $(( (b-1) & 255 ))
